value.check:
if (!world.getEntity(action.object).properties.fixedWithLever) {
  return "The turnstile won't budge. It's missing a lever or handle to give you any leverage.";
}

value.perform:
const turnstile = world.getEntity(action.object);
const exit = world.getEntity("exit:gate:north");
world.updateEntity(exit, { properties: { ...exit.properties, locked: false } });
return "With the lever in place, the turnstile rotates with a series of heavy, metallic clicks. The way north into the market is now clear.";

